class _DB:
    def __init__(self):
        self._tables = {}
    def create_table(self, name, schema=None):
        if name not in self._tables:
            self._tables[name] = {"schema": schema or {}, "records": [], "next_id": 1}
    def query(self, table, filter=None):
        self.create_table(table)
        records = self._tables[table]["records"]
        if not filter: return list(records)
        return [r for r in records if all(r.get(k) == v for k, v in filter.items())]
    def query_one(self, table, filter=None):
        results = self.query(table, filter)
        return results[0] if results else None
    def save(self, table, record):
        self.create_table(table)
        store = self._tables[table]
        new_record = {**record, "id": store["next_id"]}
        store["next_id"] += 1
        store["records"].append(new_record)
        return new_record
    def update(self, table, record):
        self.create_table(table)
        for r in self._tables[table]["records"]:
            if r.get("id") == record.get("id"):
                r.update(record)
                return 1
        return 0
    def remove(self, table, filter=None):
        self.create_table(table)
        store = self._tables[table]
        before = len(store["records"])
        if not filter: store["records"] = []
        else: store["records"] = [r for r in store["records"] if not all(r.get(k) == v for k, v in filter.items())]
        return before - len(store["records"])
